   113→            char *endptr;
   114→            uid = strtol(user, &endptr, 10);
   115→            if (errno || endptr == user)
   116→                uid = -1;
   117→        }
   118→
   119→#ifdef HAVE_GETPWNAM_R
   120→        struct passwd pwdbuf, *pwd;
   121→        memset(&pwdbuf, 0, sizeof(struct passwd));
   122→        size_t buflen;
   123→        int err;
   124→
   125→        for (buflen = 128;; buflen *= 2) {
   126→            char buf[buflen];  /* variable length array */
   127→
   128→            /* Note that we use getpwnam_r() instead of getpwnam(),
   129→             * which returns its result in a statically allocated buffer and
   130→             * cannot be considered thread safe. */
   131→            err = uid >= 0 ? getpwuid_r((uid_t)uid, &pwdbuf, buf, buflen, &pwd)
   132→                : getpwnam_r(user, &pwdbuf, buf, buflen, &pwd);
