   134→            if (err == 0 && pwd) {
   135→                /* setgid first, because we may not be allowed to do it anymore after setuid */
   136→                if (setgid(pwd->pw_gid) != 0) {
   137→                    LOGE(
   138→                        "Could not change group id to that of run_as user '%s': %s",
   139→                        pwd->pw_name, strerror(errno));
   140→                    return 0;
   141→                }
   142→
   143→                if (initgroups(pwd->pw_name, pwd->pw_gid) == -1) {
   144→                    LOGE("Could not change supplementary groups for user '%s'.", pwd->pw_name);
   145→                    return 0;
   146→                }
   147→
   148→                if (setuid(pwd->pw_uid) != 0) {
   149→                    LOGE(
   150→                        "Could not change user id to that of run_as user '%s': %s",
   151→                        pwd->pw_name, strerror(errno));
   152→                    return 0;
   153→                }
   154→                break;
   155→            } else if (err != ERANGE) {
   156→                if (err) {
