   370→void
   371→daemonize(const char *path)
   372→{
   373→#ifndef __MINGW32__
   374→    /* Our process ID and Session ID */
   375→    pid_t pid, sid;
   376→
   377→    /* Fork off the parent process */
   378→    pid = fork();
   379→    if (pid < 0) {
   380→        exit(EXIT_FAILURE);
   381→    }
   382→
   383→    /* If we got a good PID, then
   384→     * we can exit the parent process. */
   385→    if (pid > 0) {
   386→        FILE *file = fopen(path, "w");
   387→        if (file == NULL) {
   388→            FATAL("Invalid pid file\n");
   389→        }
   390→
   391→        fprintf(file, "%d", (int)pid);
   392→        fclose(file);
   393→        exit(EXIT_SUCCESS);
   394→    }
   395→
   396→    /* Change the file mode mask */
   397→    umask(0);
   398→
   399→    /* Open any logs here */
   400→
   401→    /* Create a new SID for the child process */
   402→    sid = setsid();
   403→    if (sid < 0) {
   404→        /* Log the failure */
   405→        exit(EXIT_FAILURE);
   406→    }
   407→
   408→    /* Change the current working directory */
   409→    if ((chdir("/")) < 0) {
   410→        /* Log the failure */
   411→        exit(EXIT_FAILURE);
   412→    }
   413→
   414→    /* Close out the standard file descriptors */
   415→    close(STDIN_FILENO);
   416→    close(STDOUT_FILENO);
   417→    close(STDERR_FILENO);
   418→#endif
